def parse_supplier_file(path):
    fn=os.path.basename(path); txt=open(path).read()
    day=int(re.search(r'day_(\d+)',fn).group(1)); pr=re.search(r'_(PR_\d+)_',fn).group(1)
    items=[]
    if fn.endswith('.json'):
        o=json.loads(txt); pr=o['supplier_id']; day=int(re.search(r'Day_(\d+)',o['date']).group(1)); items=[(it['prod_id'],int(it['delivered_qty'])) for it in o['items']]
    elif 'table-csv' in fn:
        for line in txt.strip().splitlines()[1:]:
            if not line.strip(): continue
            p,q=line.split(';'); items.append((p,int(q)))
    elif 'key-value' in fn:
        m=re.search(r'SUPPLIER: (PR_\d+) \| DAY: (\d+)',txt); pr=m.group(1); day=int(m.group(2))
        items=[(p,int(q)) for p,q in re.findall(r'PRODUCT: (P_\d+) \| DELIVERED_QTY: (\d+)',txt)]
    elif 'text-template' in fn:
        # Supplier PR_10 delivered 12 units of product P_1 to the wholesaler on Day_1.
        rows=re.findall(r'Supplier (PR_\d+) delivered (\d+) units of product (P_\d+) .* Day_(\d+)',txt)
        items=[]
        for pr2,q,p,d in rows:
            pr=pr2; day=int(d); items.append((p,int(q)))
    return day,pr,items

def parse_order_file(path):
    fn=os.path.basename(path); txt=open(path).read()
    day=int(re.search(r'day_(\d+)',fn).group(1)); store=re.search(r'_(S_\d+)_',fn).group(1)
    items=[]
