    elif 'table-csv' in fn:
        for line in txt.strip().splitlines()[1:]:
            if not line.strip(): continue
            p,q=line.split(';'); items.append((p,int(q)))
    elif 'key-value' in fn:
        rows=re.findall(r'RECEIVER: (S_\d+) \| ORDER_PRODUCT: (P_\d+) \| ORDER_QTY: (\d+)',txt)
